function process(context, message) {
  // Get the name from the input record
  var name = message.getString('name');

  // Create greeting
  var greeting = "Hello, " + name + "!";

  // Add greeting to the message
  message.setString('greeting', greeting);

  // Log for visibility
  logger.info('Greeting created: ' + greeting);

  return message;
}
